class Solution:
    def numberOfSubstrings(self, s: str) -> int:
        n = len(s)
        count = 0
        left = 0
        d = {"a" : 0, "b" : 0, "c" : 0}
        # for i in range(n - 2):
        #     for j in range(i + 2, n):
        #         d[s[j]] += 1 # добавляем букву
        #         if d['a'] > 0 and d['b'] > 0 and d['c'] > 0:
        #             count += n - j
        #             d[s[j]] -= 1
        #             break
        # return count
        for r in range(n):
            d[s[r]] += 1 # добавляем букву
            while d['a'] > 0 and d['b'] > 0 and d['c'] > 0:
                count += n - r
                d[s[left]] -= 1
                left += 1
        return count




print(Solution().numberOfSubstrings("abcabc") == 10)
print(Solution().numberOfSubstrings("aaacb") == 3)
print(Solution().numberOfSubstrings("abc") == 1)
print(Solution().numberOfSubstrings("ababbbc") == 3)
print(Solution().numberOfSubstrings("acbbcac") == 11)
print(Solution().numberOfSubstrings("cabbcbc") == 8)
print(Solution().numberOfSubstrings("") == 45830534)
